THE CLAIM:
{
 "title": "Geography weights overstate Netherlands, understate Switzerland",
 "narrative": "The model splits geography by colocation megawatts, then applies that split to the 29% enterprise slice. But colocation covers only about two-thirds of Europe's IT power, and enterprise machine rooms sit where industry is, not where Amsterdam campuses are. So the Netherlands cell counts enterprise demand that physically sits in German and Swiss server rooms, and anyone staffing a DACH channel off these weights will pick the wrong countries.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Colocation covers only two-thirds of Europe's IT power.",
   "refs": [
    "digest:geo-region-denominator#c11",
    "ledger:geo.NL"
   ]
  },
  {
   "step": "propagation",
   "text": "The missing third sits elsewhere; Switzerland runs 0.13 versus 0.08.",
   "refs": [
    "ledger:geo.CH",
    "ledger:geo.DE",
    "ledger:seg.enterprise"
   ]
  },
  {
   "step": "model-impact",
   "text": "Netherlands is overstated, Switzerland undersized, across the 29% enterprise slice.",
   "refs": [
    "ledger:geo.NL",
    "ledger:geo.CH",
    "ledger:seg.enterprise"
   ]
  }
 ],
 "falsifier": "A country-level installed-load table showing the Netherlands share of total load near its colocation share of 0.28, meaning the missing third distributes the same way.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "New 2026 State of European Data Centres",
   "sourceType": "industry-report",
   "publisher": "EUDCA",
   "date": "2026",
   "excerpt": "The 2026 edition shows that commercial colocation and hyperscale facilities now provide more than two-thirds of Europe’s IT power, driven by the growing demand for cloud and AI.",
   "url": "https://www.eudca.org/new-2026-state-of-european-data-centres",
   "attached": true
  },
  {
   "title": "Status and development of the German data centre landscape – Executive Summary",
   "sourceType": "industry-report",
   "publisher": "BMWK (German Federal Ministry for Economic Affairs)",
   "date": "2025-03",
   "excerpt": "With over 2,000 data centres and an installed IT power demand of over 2,700 MW, Germany is already the largest centre for digital infrastructure in Europe.",
   "url": "https://www.bundeswirtschaftsministerium.de/Redaktion/EN/Publikationen/Digitale-Welt/status-and-development-of-the-german-data-centre-landscape-executive-summary.pdf?__blob=publicationFile&v=2",
   "attached": true
  },
  {
   "title": "Data Center Impact Report Deutschland",
   "sourceType": "industry-report",
   "publisher": "German Datacenters Association",
   "date": "2024",
   "excerpt": "1,955 MW IT power in Germany approx. ... thereof 69 % in colocation data centers",
   "url": "https://www.germandatacenters.com/fileadmin/images/DCIRD-24/Data-Center-Impact-Report-Deutschland-2024_EN.pdf",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "geo.NL",
  "label": "Netherlands",
  "kind": "estimated",
  "value": 0.28,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": "geography",
  "dimensionValue": "NL",
  "sensitivityRange": {
   "low": 0.24,
   "high": 0.31
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "NL colo 951 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.276 → 0.28 (normalized)",
   "crossCheck": "Dutch Data Center Association: national colo 924 MW (2024) — consistent scale"
  },
  "provenance": {
   "rationale": "Statista and the national association agree within ~3% → inferred, triangulated."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Netherlands 951 MW of colocation and scale-colocation IT power in 2025.",
    "attached": true
   },
   {
    "title": "Ten years of State of the Dutch Data Centers",
    "sourceType": "industry-report",
    "publisher": "Dutch Data Center Association",
    "date": "2024",
    "excerpt": "In 2024, the total colocation capacity reached 924 megawatts... the Amsterdam Metropolitan Area still accounts for approximately 70% of colocation capacity.",
    "attached": true
   }
  ]
 },
 {
  "id": "geo.CH",
  "label": "Switzerland",
  "kind": "estimated",
  "value": 0.08,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": "geography",
  "dimensionValue": "CH",
  "sensitivityRange": {
   "low": 0.07,
   "high": 0.13
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "CH colo 274 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.079 → 0.08 (normalized)",
   "crossCheck": "Installed-base method (Mordor 850.6 MW incl. self-operated) → ~0.13 — Swiss market is self-operation-heavy"
  },
  "provenance": {
   "rationale": "Large self-operated share (CBRE Suisse: 340 MW commercial only) makes scope choice decisive → inferred, wide band."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Switzerland 274 MW of colocation and scale-colocation IT power in 2025.",
    "attached": true
   },
   {
    "title": "CBRE Suisse — Swiss data-center market capacity",
    "sourceType": "analyst-estimate",
    "publisher": "CBRE Suisse",
    "date": "2026",
    "excerpt": "Commercial capacity (excluding self-operated infrastructure) is 340 MW across 121 sites; ~61% (209 MW) concentrated in the Zurich region.",
    "attached": true
   }
  ]
 },
 {
  "id": "seg.enterprise",
  "label": "Enterprise",
  "kind": "estimated",
  "value": 0.29,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": "segment",
  "dimensionValue": "enterprise",
  "sensitivityRange": {
   "low": 0.24,
   "high": 0.3
  },
  "funnelActive": true,
  "derivation": {
   "method": "Capacity-split rescaling",
   "expression": "Synergy end-2025 enterprise on-premise 32% × 0.91 = 0.29",
   "crossCheck": "Refinement cycle 1: NVIDIA's B300 reference architectures ship rack PDUs in both AC and DC variants (3 per rack / 160 per pod) — GPU growth is PDU-consuming. Value confirmed; downside band covers dense busbar deployments."
  },
  "provenance": {
   "rationale": "Single publisher's capacity series, but the 'GPU pods skip PDUs' doubt was refuted by vendor reference architectures (refinement cycle 1) → value confirmed with a downside band."
  },
  "evidence": [
   {
    "title": "Hyperscale operators to account for 67% of all data center capacity by 2031",
    "sourceType": "industry-report",
    "publisher": "Synergy Research Group",
    "date": "2026",
    "excerpt": "That leaves enterprise on-premise data centers with just 32% of the total — down from 56% in 2018, heading to 19% by 2031.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
